INSERT OR IGNORE INTO skills (id,skillset_id,name,description,x_pos,y_pos,color) VALUES (77,7,'20 SECOND RULE','After Hajime is called, asses the rival for some seconds. Do not rush to engage without understanding where he stands, what he aims to do.',350.0,280.0,'#0000ff');
INSERT OR IGNORE INTO skills (id,skillset_id,name,description,x_pos,y_pos,color) VALUES (78,7,'GENTLE PUSH','If the opponent is close enough to the edge of the shiaijo, and the situation allows for it without an excesive use of the brute force. Help him out the shiajo, so you secure a hansoku against him.',495.4475635457604,280.5710441726405,'#0000ff');
INSERT OR IGNORE INTO skills (id,skillset_id,name,description,x_pos,y_pos,color) VALUES (79,7,'COOL DOWN','The most common way to lose a point is right after you have scored/ your opponent has scored. Take some time to cool down before the fight restarts. Engange with control, not with eagerness.',629.6771668414846,280.3299999586477,'#0000ff');
INSERT OR IGNORE INTO skills (id,skillset_id,name,description,x_pos,y_pos,color) VALUES (80,7,'WAKARESAI NO KIWA','New rules avoid the "fake retreat" situation, but the "dissengagement" rules apply only if BOTH agree to the wakare. If you do not do it, and your opponent does, use the opening for an easy ippon.',785.146962804486,280.3356378657577,'#002aff');
